308: class FilterConfigPerRoute : public Router::RouteSpecificFilterConfig {
309: public:
310:   using ContextExtensionsMap = Protobuf::Map<std::string, std::string>;
311: 
312:   FilterConfigPerRoute(
313:       const envoy::extensions::filters::http::ext_authz::v3::ExtAuthzPerRoute& config)
314:       : context_extensions_(config.has_check_settings()
315:                                 ? config.check_settings().context_extensions()
316:                                 : ContextExtensionsMap()),
317:         check_settings_(config.has_check_settings()
318:                             ? config.check_settings()
319:                             : envoy::extensions::filters::http::ext_authz::v3::CheckSettings()),
320:         disabled_(config.disabled()),
321:         grpc_service_(config.has_check_settings() && config.check_settings().has_grpc_service()
322:                           ? absl::make_optional(config.check_settings().grpc_service())
323:                           : absl::nullopt),
324:         http_service_(config.has_check_settings() && config.check_settings().has_http_service()
325:                           ? absl::make_optional(config.check_settings().http_service())
326:                           : absl::nullopt) {
327:     if (config.has_check_settings() && config.check_settings().disable_request_body_buffering() &&
328:         config.check_settings().has_with_request_body()) {
329:       ExceptionUtil::throwEnvoyException(
330:           "Invalid configuration for check_settings. Only one of disable_request_body_buffering or "
331:           "with_request_body can be set.");
332:     }
333:   }
334: 
335:   // This constructor is used as a way to merge more-specific config into less-specific config in a
336:   // clearly defined way (e.g. route config into VH config). All fields on this class must be const
337:   // and thus must be initialized in the constructor initialization list.
338:   FilterConfigPerRoute(const FilterConfigPerRoute& less_specific,
339:                        const FilterConfigPerRoute& more_specific);
340: 
341:   void merge(const FilterConfigPerRoute& other);
342: 
343:   /**
344:    * @return Context extensions to add to the CheckRequest.
345:    */
346:   const ContextExtensionsMap& contextExtensions() const { return context_extensions_; }
347:   // Allow moving the context extensions out of this object.
348:   ContextExtensionsMap&& takeContextExtensions() { return std::move(context_extensions_); }
349: 
350:   bool disabled() const { return disabled_; }
351: 
352:   const envoy::extensions::filters::http::ext_authz::v3::CheckSettings& checkSettings() const {
353:     return check_settings_;
354:   }
355: 
356:   /**
357:    * @return The gRPC service override for this route, if any.
358:    */
359:   const absl::optional<const envoy::config::core::v3::GrpcService>& grpcService() const {
360:     return grpc_service_;
361:   }
362: 
363:   /**
364:    * @return The HTTP service override for this route, if any.
365:    */
366:   const absl::optional<const envoy::extensions::filters::http::ext_authz::v3::HttpService>&
367:   httpService() const {
368:     return http_service_;
369:   }
370: 
371: private:
372:   // We save the context extensions as a protobuf map instead of a std::map as this allows us to
373:   // move it to the CheckRequest, thus avoiding a copy that would incur by converting it.
374:   ContextExtensionsMap context_extensions_;
375:   envoy::extensions::filters::http::ext_authz::v3::CheckSettings check_settings_;
376:   const bool disabled_;
377:   const absl::optional<const envoy::config::core::v3::GrpcService> grpc_service_;
378:   const absl::optional<const envoy::extensions::filters::http::ext_authz::v3::HttpService>
379:       http_service_;
380: };
