31: void fillMetadataContext(const std::vector<const MetadataProto*>& source_metadata,
32:                          const std::vector<std::string>& metadata_context_namespaces,
33:                          const std::vector<std::string>& typed_metadata_context_namespaces,
34:                          MetadataProto& metadata_context) {
35:   for (const auto& context_key : metadata_context_namespaces) {
36:     for (const MetadataProto* metadata : source_metadata) {
37:       if (metadata == nullptr) {
38:         continue;
39:       }
40:       const auto& filter_metadata = metadata->filter_metadata();
41:       if (const auto metadata_it = filter_metadata.find(context_key);
42:           metadata_it != filter_metadata.end()) {
43:         (*metadata_context.mutable_filter_metadata())[metadata_it->first] = metadata_it->second;
44:         break;
45:       }
46:     }
47:   }
48: 
49:   for (const auto& context_key : typed_metadata_context_namespaces) {
50:     for (const MetadataProto* metadata : source_metadata) {
51:       if (metadata == nullptr) {
52:         continue;
53:       }
54:       const auto& typed_filter_metadata = metadata->typed_filter_metadata();
55:       if (const auto metadata_it = typed_filter_metadata.find(context_key);
56:           metadata_it != typed_filter_metadata.end()) {
57:         (*metadata_context.mutable_typed_filter_metadata())[metadata_it->first] =
58:             metadata_it->second;
59:         break;
60:       }
61:     }
62:   }
63: }
