84:       max_request_bytes_(config.with_request_body().max_request_bytes()),
85:       max_denied_response_body_bytes_(config.max_denied_response_body_bytes()),
86: 
87:       // `pack_as_bytes_` should be true when configured with the HTTP service because there is no
88:       // difference to where the body is written in http requests, and a value of false here will
89:       // cause non UTF-8 body content to be changed when it doesn't need to.
90:       pack_as_bytes_(config.has_http_service() || config.with_request_body().pack_as_bytes()),
91: 
92:       encode_raw_headers_(config.encode_raw_headers()),
93: 
94:       status_on_error_(toErrorCode(config.status_on_error().code())),
95:       validate_mutations_(config.validate_mutations()), scope_(scope),
96:       decoder_header_mutation_checker_(
97:           config.has_decoder_header_mutation_rules()
98:               ? absl::optional<Filters::Common::MutationRules::Checker>(
99:                     Filters::Common::MutationRules::Checker(config.decoder_header_mutation_rules(),
100:                                                             factory_context.regexEngine()))
101:               : absl::nullopt),
102:       enable_dynamic_metadata_ingestion_(
103:           PROTOBUF_GET_WRAPPED_OR_DEFAULT(config, enable_dynamic_metadata_ingestion, true)),
104:       runtime_(factory_context.runtime()), http_context_(factory_context.httpContext()),
105:       filter_metadata_(config.has_filter_metadata() ? absl::optional(config.filter_metadata())
106:                                                     : absl::nullopt),
107:       emit_filter_state_stats_(config.emit_filter_state_stats()),
108:       enforce_response_header_limits_(config.enforce_response_header_limits()),
109:       filter_enabled_(config.has_filter_enabled()
110:                           ? absl::optional<Runtime::FractionalPercent>(
111:                                 Runtime::FractionalPercent(config.filter_enabled(), runtime_))
112:                           : absl::nullopt),
113:       filter_enabled_metadata_(
114:           config.has_filter_enabled_metadata()
115:               ? absl::optional<Matchers::MetadataMatcher>(
116:                     Matchers::MetadataMatcher(config.filter_enabled_metadata(), factory_context))
117:               : absl::nullopt),
118:       deny_at_disable_(config.has_deny_at_disable()
119:                            ? absl::optional<Runtime::FeatureFlag>(
120:                                  Runtime::FeatureFlag(config.deny_at_disable(), runtime_))
121:                            : absl::nullopt),
122:       pool_(scope_.symbolTable()),
123:       metadata_context_namespaces_(config.metadata_context_namespaces().begin(),
124:                                    config.metadata_context_namespaces().end()),
125:       typed_metadata_context_namespaces_(config.typed_metadata_context_namespaces().begin(),
126:                                          config.typed_metadata_context_namespaces().end()),
127:       route_metadata_context_namespaces_(config.route_metadata_context_namespaces().begin(),
128:                                          config.route_metadata_context_namespaces().end()),
129:       route_typed_metadata_context_namespaces_(
130:           config.route_typed_metadata_context_namespaces().begin(),
131:           config.route_typed_metadata_context_namespaces().end()),
132:       include_peer_certificate_(config.include_peer_certificate()),
133:       include_tls_session_(config.include_tls_session()),
134:       charge_cluster_response_stats_(
135:           PROTOBUF_GET_WRAPPED_OR_DEFAULT(config, charge_cluster_response_stats, true)),
136:       stats_(generateStats(stats_prefix, config.stat_prefix(), scope)),
137:       ext_authz_ok_(pool_.add(createPoolStatName(config.stat_prefix(), "ok"))),
138:       ext_authz_denied_(pool_.add(createPoolStatName(config.stat_prefix(), "denied"))),
139:       ext_authz_error_(pool_.add(createPoolStatName(config.stat_prefix(), "error"))),
140:       ext_authz_invalid_(pool_.add(createPoolStatName(config.stat_prefix(), "invalid"))),
141:       ext_authz_failure_mode_allowed_(
142:           pool_.add(createPoolStatName(config.stat_prefix(), "failure_mode_allowed"))) {
143:   auto bootstrap = factory_context.bootstrap();
144:   auto labels_key_it =
145:       bootstrap.node().metadata().fields().find(config.bootstrap_metadata_labels_key());
146:   if (labels_key_it != bootstrap.node().metadata().fields().end()) {
147:     for (const auto& labels_it : labels_key_it->second.struct_value().fields()) {
148:       destination_labels_[labels_it.first] = labels_it.second.string_value();
149:     }
150:   }
151: 
152:   if (config.has_allowed_headers() &&
153:       config.http_service().authorization_request().has_allowed_headers()) {
154:     throw EnvoyException("Invalid duplicate configuration for allowed_headers.");
155:   }
156: 
157:   // An unset request_headers_matchers_ means that all client request headers are allowed through
158:   // to the authz server; this is to preserve backwards compatibility when introducing
159:   // allowlisting of request headers for gRPC authz servers. Pre-existing support is for
160:   // HTTP authz servers only and defaults to blocking all but a few headers (i.e. Authorization,
161:   // Method, Path and Host).
162:   if (config.has_grpc_service() && config.has_allowed_headers()) {
163:     allowed_headers_matcher_ = Filters::Common::ExtAuthz::CheckRequestUtils::toRequestMatchers(
164:         config.allowed_headers(), false, factory_context);
165:   } else if (config.has_http_service()) {
166:     if (config.http_service().authorization_request().has_allowed_headers()) {
167:       allowed_headers_matcher_ = Filters::Common::ExtAuthz::CheckRequestUtils::toRequestMatchers(
168:           config.http_service().authorization_request().allowed_headers(), true, factory_context);
169:     } else {
170:       allowed_headers_matcher_ = Filters::Common::ExtAuthz::CheckRequestUtils::toRequestMatchers(
171:           config.allowed_headers(), true, factory_context);
172:     }
173:   }
174:   if (config.has_disallowed_headers()) {
175:     disallowed_headers_matcher_ = Filters::Common::ExtAuthz::CheckRequestUtils::toRequestMatchers(
176:         config.disallowed_headers(), false, factory_context);
177:   }
