180: void FilterConfigPerRoute::merge(const FilterConfigPerRoute& other) {
181:   // We only merge context extensions here, and leave boolean flags untouched since those flags are
182:   // not used from the merged config.
183:   auto begin_it = other.context_extensions_.begin();
184:   auto end_it = other.context_extensions_.end();
185:   for (auto it = begin_it; it != end_it; ++it) {
186:     context_extensions_[it->first] = it->second;
187:   }
188: }
