190: // Constructor used for merging configurations from different levels (vhost, route, etc.)
191: FilterConfigPerRoute::FilterConfigPerRoute(const FilterConfigPerRoute& less_specific,
192:                                            const FilterConfigPerRoute& more_specific)
193:     : context_extensions_(less_specific.context_extensions_),
194:       check_settings_(more_specific.check_settings_), disabled_(more_specific.disabled_),
195:       // Only use the most specific per-route override. Do not inherit overrides from less
196:       // specific configuration. If the more specific configuration has no override, leave both
197:       // unset so that the main filter configuration is used.
198:       grpc_service_(more_specific.grpc_service_.has_value() ? more_specific.grpc_service_
199:                                                             : absl::nullopt),
200:       http_service_(more_specific.http_service_.has_value() ? more_specific.http_service_
201:                                                             : absl::nullopt) {
202:   // Merge context extensions from more specific configuration, overriding less specific ones.
203:   for (const auto& extension : more_specific.context_extensions_) {
204:     context_extensions_[extension.first] = extension.second;
205:   }
206: }
