208: Filters::Common::ExtAuthz::ClientPtr
209: Filter::createPerRouteGrpcClient(const envoy::config::core::v3::GrpcService& grpc_service) {
210:   if (server_context_ == nullptr) {
211:     ENVOY_STREAM_LOG(
212:         debug, "ext_authz filter: server context not available for per-route gRPC client creation.",
213:         *decoder_callbacks_);
214:     return nullptr;
215:   }
216: 
217:   // Use the timeout from the gRPC service configuration, use default if not specified.
218:   // A timeout of 0 means infinite (no timeout). Convert to nullopt in that case.
219:   const uint32_t timeout_ms =
220:       PROTOBUF_GET_MS_OR_DEFAULT(grpc_service, timeout, kDefaultPerRouteTimeoutMs);
221:   const absl::optional<std::chrono::milliseconds> timeout =
222:       timeout_ms == 0
223:           ? absl::nullopt
224:           : absl::optional<std::chrono::milliseconds>(std::chrono::milliseconds(timeout_ms));
225: 
226:   // We can skip transport version check for per-route gRPC service here.
227:   // The transport version is already validated at the main configuration level.
228:   Envoy::Grpc::GrpcServiceConfigWithHashKey config_with_hash_key =
229:       Envoy::Grpc::GrpcServiceConfigWithHashKey(grpc_service);
230: 
231:   auto client_or_error = server_context_->clusterManager()
232:                              .grpcAsyncClientManager()
233:                              .getOrCreateRawAsyncClientWithHashKey(config_with_hash_key,
234:                                                                    server_context_->scope(), true);
235:   if (!client_or_error.ok()) {
236:     ENVOY_STREAM_LOG(warn,
237:                      "ext_authz filter: failed to create per-route gRPC client: {}. Falling back "
238:                      "to default client.",
239:                      *decoder_callbacks_, client_or_error.status().ToString());
240:     return nullptr;
241:   }
242: 
243:   ENVOY_STREAM_LOG(debug, "ext_authz filter: created per-route gRPC client for cluster: {}.",
244:                    *decoder_callbacks_,
245:                    grpc_service.has_envoy_grpc() ? grpc_service.envoy_grpc().cluster_name()
246:                                                  : "google_grpc");
247: 
248:   return std::make_unique<Filters::Common::ExtAuthz::GrpcClientImpl>(client_or_error.value(),
249:                                                                      timeout);
250: }
