275: void Filter::initiateCall(const Http::RequestHeaderMap& headers) {
276:   if (filter_return_ == FilterReturn::StopDecoding) {
277:     return;
278:   }
279: 
280:   // Now that we'll definitely be making the request, add filter state stats if configured to do so.
281:   const Envoy::StreamInfo::FilterStateSharedPtr& filter_state =
282:       decoder_callbacks_->streamInfo().filterState();
283:   if ((config_->emitFilterStateStats() || config_->filterMetadata().has_value())) {
284:     if (!filter_state->hasData<ExtAuthzLoggingInfo>(decoder_callbacks_->filterConfigName())) {
285:       filter_state->setData(decoder_callbacks_->filterConfigName(),
286:                             std::make_shared<ExtAuthzLoggingInfo>(config_->filterMetadata()),
287:                             Envoy::StreamInfo::FilterState::StateType::Mutable,
288:                             Envoy::StreamInfo::FilterState::LifeSpan::Request);
289: 
290:       // This may return nullptr (if there's a value at this name whose type doesn't match or isn't
291:       // mutable, for example), so we must check logging_info_ is not nullptr later.
292:       logging_info_ =
293:           filter_state->getDataMutable<ExtAuthzLoggingInfo>(decoder_callbacks_->filterConfigName());
294:     }
295:     if (logging_info_ == nullptr) {
296:       stats_.filter_state_name_collision_.inc();
297:       ENVOY_STREAM_LOG(debug,
298:                        "Could not find logging info at {}! (Did another filter already put data "
299:                        "at this name?)",
300:                        *decoder_callbacks_, decoder_callbacks_->filterConfigName());
301:     }
302:   }
303: 
304:   absl::optional<FilterConfigPerRoute> maybe_merged_per_route_config;
305:   for (const FilterConfigPerRoute& cfg :
306:        Http::Utility::getAllPerFilterConfig<FilterConfigPerRoute>(decoder_callbacks_)) {
307:     if (maybe_merged_per_route_config.has_value()) {
308:       FilterConfigPerRoute current_config = maybe_merged_per_route_config.value();
309:       maybe_merged_per_route_config.emplace(current_config, cfg);
310:     } else {
311:       maybe_merged_per_route_config.emplace(cfg);
312:     }
313:   }
314: 
315:   Protobuf::Map<std::string, std::string> context_extensions;
316:   if (maybe_merged_per_route_config) {
317:     context_extensions = maybe_merged_per_route_config.value().takeContextExtensions();
318:   }
319: 
320:   // Check if we need to use a per-route service override (gRPC or HTTP).
321:   if (maybe_merged_per_route_config) {
322:     if (maybe_merged_per_route_config->grpcService().has_value()) {
323:       const auto& grpc_service = maybe_merged_per_route_config->grpcService().value();
324:       ENVOY_STREAM_LOG(debug, "ext_authz filter: using per-route gRPC service configuration.",
325:                        *decoder_callbacks_);
326: 
327:       // Create a new gRPC client for this route.
328:       auto per_route_client = createPerRouteGrpcClient(grpc_service);
329:       if (per_route_client != nullptr) {
330:         client_ = std::move(per_route_client);
331:         ENVOY_STREAM_LOG(debug, "ext_authz filter: successfully created per-route gRPC client.",
332:                          *decoder_callbacks_);
333:       } else {
334:         ENVOY_STREAM_LOG(
335:             warn,
336:             "ext_authz filter: failed to create per-route gRPC client, falling back to default.",
337:             *decoder_callbacks_);
338:       }
339:     } else if (maybe_merged_per_route_config->httpService().has_value()) {
340:       const auto& http_service = maybe_merged_per_route_config->httpService().value();
341:       ENVOY_STREAM_LOG(debug, "ext_authz filter: using per-route HTTP service configuration.",
342:                        *decoder_callbacks_);
343: 
344:       // Create a new HTTP client for this route.
345:       auto per_route_client = createPerRouteHttpClient(http_service);
346:       if (per_route_client != nullptr) {
347:         client_ = std::move(per_route_client);
348:         ENVOY_STREAM_LOG(debug, "ext_authz filter: successfully created per-route HTTP client.",
349:                          *decoder_callbacks_);
350:       } else {
351:         ENVOY_STREAM_LOG(
352:             warn,
353:             "ext_authz filter: failed to create per-route HTTP client, falling back to default.",
354:             *decoder_callbacks_);
355:       }
356:     }
357:   }
358: 
359:   // If metadata_context_namespaces or typed_metadata_context_namespaces is specified,
360:   // pass matching filter metadata to the ext_authz service.
361:   // If metadata key is set in both the connection and request metadata,
362:   // then the value will be the request metadata value.
363:   envoy::config::core::v3::Metadata metadata_context;
364:   fillMetadataContext({&decoder_callbacks_->streamInfo().dynamicMetadata(),
365:                        &decoder_callbacks_->connection()->streamInfo().dynamicMetadata()},
366:                       config_->metadataContextNamespaces(),
367:                       config_->typedMetadataContextNamespaces(), metadata_context);
368: 
369:   // Fill route_metadata_context from the selected route's metadata.
370:   envoy::config::core::v3::Metadata route_metadata_context;
371:   if (decoder_callbacks_->route() != nullptr) {
372:     fillMetadataContext({&decoder_callbacks_->route()->metadata()},
373:                         config_->routeMetadataContextNamespaces(),
374:                         config_->routeTypedMetadataContextNamespaces(), route_metadata_context);
375:   }
376: 
377:   Filters::Common::ExtAuthz::CheckRequestUtils::createHttpCheck(
378:       decoder_callbacks_, headers, std::move(context_extensions), std::move(metadata_context),
379:       std::move(route_metadata_context), check_request_, max_request_bytes_, config_->packAsBytes(),
380:       config_->headersAsBytes(), config_->includePeerCertificate(), config_->includeTLSSession(),
381:       config_->destinationLabels(), config_->allowedHeadersMatcher(),
382:       config_->disallowedHeadersMatcher());
383: 
384:   ENVOY_STREAM_LOG(trace, "ext_authz filter calling authorization server.", *decoder_callbacks_);
385:   // Store start time of ext_authz filter call
386:   start_time_ = decoder_callbacks_->dispatcher().timeSource().monotonicTime();
387: 
388:   state_ = State::Calling;
389:   filter_return_ = FilterReturn::StopDecoding; // Don't let the filter chain continue as we are
390:                                                // going to invoke check call.
391:   cluster_ = decoder_callbacks_->clusterInfo();
392:   initiating_call_ = true;
393:   client_->check(*this, check_request_, decoder_callbacks_->activeSpan(),
394:                  decoder_callbacks_->streamInfo());
395:   initiating_call_ = false;
396: }
