398: Http::FilterHeadersStatus Filter::decodeHeaders(Http::RequestHeaderMap& headers, bool end_stream) {
399:   Router::RouteConstSharedPtr route = decoder_callbacks_->route();
400:   const auto per_route_flags = getPerRouteFlags(route);
401:   skip_check_ = per_route_flags.skip_check_;
402:   if (skip_check_) {
403:     return Http::FilterHeadersStatus::Continue;
404:   }
405: 
406:   if (!config_->filterEnabled(decoder_callbacks_->streamInfo().dynamicMetadata())) {
407:     stats_.disabled_.inc();
408:     if (config_->denyAtDisable()) {
409:       ENVOY_STREAM_LOG(trace, "ext_authz filter is disabled. Deny the request.",
410:                        *decoder_callbacks_);
411:       decoder_callbacks_->streamInfo().setResponseFlag(
412:           StreamInfo::CoreResponseFlag::UnauthorizedExternalService);
413:       decoder_callbacks_->sendLocalReply(
414:           config_->statusOnError(), EMPTY_STRING, nullptr, absl::nullopt,
415:           Filters::Common::ExtAuthz::ResponseCodeDetails::get().AuthzError);
416:       return Http::FilterHeadersStatus::StopIteration;
417:     }
418:     return Http::FilterHeadersStatus::Continue;
419:   }
420: 
421:   request_headers_ = &headers;
422:   const auto& check_settings = per_route_flags.check_settings_;
423:   buffer_data_ = (config_->withRequestBody() || check_settings.has_with_request_body()) &&
424:                  !check_settings.disable_request_body_buffering() &&
425:                  !(end_stream || Http::Utility::isWebSocketUpgradeRequest(headers) ||
426:                    Http::Utility::isH2UpgradeRequest(headers));
427: 
428:   max_request_bytes_ = config_->maxRequestBytes();
429:   if (buffer_data_) {
430:     ENVOY_STREAM_LOG(debug, "ext_authz filter is buffering the request", *decoder_callbacks_);
431: 
432:     allow_partial_message_ = check_settings.has_with_request_body()
433:                                  ? check_settings.with_request_body().allow_partial_message()
434:                                  : config_->allowPartialMessage();
435:     if (check_settings.has_with_request_body()) {
436:       max_request_bytes_ = check_settings.with_request_body().max_request_bytes();
437:     }
438:     if (!allow_partial_message_) {
439:       decoder_callbacks_->setBufferLimit(max_request_bytes_);
440:     }
441:     return Http::FilterHeadersStatus::StopIteration;
442:   }
443: 
444:   // Initiate a call to the authorization server since we are not disabled.
445:   initiateCall(headers);
446:   return filter_return_ == FilterReturn::StopDecoding
447:              ? Http::FilterHeadersStatus::StopAllIterationAndWatermark
448:              : Http::FilterHeadersStatus::Continue;
449: }
