451: Http::FilterDataStatus Filter::decodeData(Buffer::Instance& data, bool end_stream) {
452:   if (buffer_data_ && !skip_check_) {
453:     const bool buffer_is_full = isBufferFull(data.length());
454:     if (end_stream || buffer_is_full) {
455:       ENVOY_STREAM_LOG(debug, "ext_authz filter finished buffering the request since {}",
456:                        *decoder_callbacks_, buffer_is_full ? "buffer is full" : "stream is ended");
457:       // Make sure data is available in initiateCall.
458:       decoder_callbacks_->addDecodedData(data, true);
459:       initiateCall(*request_headers_);
460:       return filter_return_ == FilterReturn::StopDecoding
461:                  ? Http::FilterDataStatus::StopIterationAndWatermark
462:                  : Http::FilterDataStatus::Continue;
463:     } else {
464:       return Http::FilterDataStatus::StopIterationAndBuffer;
465:     }
466:   }
467: 
468:   return Http::FilterDataStatus::Continue;
469: }
