471: Http::FilterTrailersStatus Filter::decodeTrailers(Http::RequestTrailerMap&) {
472:   if (buffer_data_ && !skip_check_) {
473:     if (filter_return_ != FilterReturn::StopDecoding) {
474:       ENVOY_STREAM_LOG(debug, "ext_authz filter finished buffering the request",
475:                        *decoder_callbacks_);
476:       initiateCall(*request_headers_);
477:     }
478:     return filter_return_ == FilterReturn::StopDecoding ? Http::FilterTrailersStatus::StopIteration
479:                                                         : Http::FilterTrailersStatus::Continue;
480:   }
481: 
482:   return Http::FilterTrailersStatus::Continue;
483: }
