489: Http::FilterHeadersStatus Filter::encodeHeaders(Http::ResponseHeaderMap& headers, bool) {
490:   ENVOY_STREAM_LOG(trace,
491:                    "ext_authz filter has {} response header(s) to add and {} response header(s) to "
492:                    "set to the encoded response:",
493:                    *encoder_callbacks_, response_headers_to_add_.size(),
494:                    response_headers_to_set_.size());
495:   if (!response_headers_to_add_.empty()) {
496:     ENVOY_STREAM_LOG(
497:         trace, "ext_authz filter added header(s) to the encoded response:", *encoder_callbacks_);
498:     for (const auto& [key, value] : response_headers_to_add_) {
499:       ENVOY_STREAM_LOG(trace, "'{}':'{}'", *encoder_callbacks_, key.get(), value);
500:       headers.addCopy(key, value);
501:       if (config_->enforceResponseHeaderLimits() && !headersWithinLimits(headers)) {
502:         responseHeaderLimitsReached();
503:         return Http::FilterHeadersStatus::StopIteration;
504:       }
505:     }
506:   }
507: 
508:   if (!response_headers_to_set_.empty()) {
509:     ENVOY_STREAM_LOG(
510:         trace, "ext_authz filter set header(s) to the encoded response:", *encoder_callbacks_);
511:     for (const auto& [key, value] : response_headers_to_set_) {
512:       ENVOY_STREAM_LOG(trace, "'{}':'{}'", *encoder_callbacks_, key.get(), value);
513:       headers.setCopy(key, value);
514:       if (config_->enforceResponseHeaderLimits() && !headersWithinLimits(headers)) {
515:         responseHeaderLimitsReached();
516:         return Http::FilterHeadersStatus::StopIteration;
517:       }
518:     }
519:   }
520: 
521:   if (!response_headers_to_add_if_absent_.empty()) {
522:     for (const auto& [key, value] : response_headers_to_add_if_absent_) {
523:       ENVOY_STREAM_LOG(trace, "'{}':'{}'", *encoder_callbacks_, key.get(), value);
524:       if (auto header_entry = headers.get(key); header_entry.empty()) {
525:         ENVOY_STREAM_LOG(trace, "ext_authz filter added header(s) to the encoded response:",
526:                          *encoder_callbacks_);
527:         headers.addCopy(key, value);
528:         if (config_->enforceResponseHeaderLimits() && !headersWithinLimits(headers)) {
529:           responseHeaderLimitsReached();
530:           return Http::FilterHeadersStatus::StopIteration;
531:         }
532:       }
533:     }
534:   }
535: 
536:   if (!response_headers_to_overwrite_if_exists_.empty()) {
537:     for (const auto& [key, value] : response_headers_to_overwrite_if_exists_) {
538:       ENVOY_STREAM_LOG(trace, "'{}':'{}'", *encoder_callbacks_, key, value);
539:       if (auto header_entry = headers.get(key); !header_entry.empty()) {
540:         ENVOY_STREAM_LOG(
541:             trace, "ext_authz filter set header(s) to the encoded response:", *encoder_callbacks_);
542:         headers.setCopy(key, value);
543:         if (config_->enforceResponseHeaderLimits() && !headersWithinLimits(headers)) {
544:           responseHeaderLimitsReached();
545:           return Http::FilterHeadersStatus::StopIteration;
546:         }
547:       }
548:     }
549:   }
550: 
551:   return Http::FilterHeadersStatus::Continue;
552: }
