570: void Filter::updateLoggingInfo(const absl::optional<Grpc::Status::GrpcStatus>& grpc_status) {
571:   if (!config_->emitFilterStateStats()) {
572:     return;
573:   }
574: 
575:   if (logging_info_ == nullptr) {
576:     return;
577:   }
578: 
579:   if (grpc_status.has_value()) {
580:     logging_info_->setGrpcStatus(grpc_status.value());
581:   }
582: 
583:   // Latency is the only stat available if we aren't using envoy grpc.
584:   if (start_time_.has_value()) {
585:     logging_info_->setLatency(std::chrono::duration_cast<std::chrono::microseconds>(
586:         decoder_callbacks_->dispatcher().timeSource().monotonicTime() - start_time_.value()));
587:   }
588: 
589:   auto const* stream_info = client_->streamInfo();
590:   if (stream_info == nullptr) {
591:     return;
592:   }
593: 
594:   const auto& bytes_meter = stream_info->getUpstreamBytesMeter();
595:   if (bytes_meter != nullptr) {
596:     logging_info_->setBytesSent(bytes_meter->wireBytesSent());
597:     logging_info_->setBytesReceived(bytes_meter->wireBytesReceived());
598:   }
599:   if (stream_info->upstreamInfo().has_value()) {
600:     logging_info_->setUpstreamHost(stream_info->upstreamInfo()->upstreamHost());
601:   }
602:   absl::optional<Upstream::ClusterInfoConstSharedPtr> cluster_info =
603:       stream_info->upstreamClusterInfo();
604:   if (cluster_info) {
605:     logging_info_->setClusterInfo(std::move(*cluster_info));
606:   }
607: }
