620: CheckResult Filter::validateAndCheckDecoderHeaderMutation(
621:     Filters::Common::MutationRules::CheckOperation operation, absl::string_view key,
622:     absl::string_view value) const {
623:   if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
624:                                        !Http::HeaderUtility::headerValueIsValid(value))) {
625:     return CheckResult::FAIL;
626:   }
627:   // Check header mutation is valid according to configured decoder mutation rules.
628:   return config_->checkDecoderHeaderMutation(operation, Http::LowerCaseString(key), value);
629: }
630: 
631: void Filter::onComplete(Filters::Common::ExtAuthz::ResponsePtr&& response) {
632:   state_ = State::Complete;
633:   using Filters::Common::ExtAuthz::CheckStatus;
634:   Stats::StatName empty_stat_name;
635: 
636:   updateLoggingInfo(response->grpc_status);
637: 
638:   if (response->saw_invalid_append_actions) {
639:     if (config_->validateMutations()) {
640:       ENVOY_STREAM_LOG(trace, "Rejecting response with invalid header append action.",
641:                        *decoder_callbacks_);
642:       rejectResponse();
643:       return;
644:     }
645:     ENVOY_STREAM_LOG(trace, "Ignoring response headers with invalid header append action.",
646:                      *decoder_callbacks_);
647:   }
648: 
649:   if (!response->dynamic_metadata.fields().empty()) {
650:     if (!config_->enableDynamicMetadataIngestion()) {
651:       ENVOY_STREAM_LOG(trace,
652:                        "Response is trying to inject dynamic metadata, but dynamic metadata "
653:                        "ingestion is disabled. Ignoring...",
654:                        *decoder_callbacks_);
655:       stats_.ignored_dynamic_metadata_.inc();
656:     } else {
657:       // Add duration of call to dynamic metadata if applicable
658:       if (start_time_.has_value() && response->status == CheckStatus::OK) {
659:         Protobuf::Value ext_authz_duration_value;
660:         auto duration =
661:             decoder_callbacks_->dispatcher().timeSource().monotonicTime() - start_time_.value();
662:         ext_authz_duration_value.set_number_value(
663:             std::chrono::duration_cast<std::chrono::milliseconds>(duration).count());
664:         (*response->dynamic_metadata.mutable_fields())["ext_authz_duration"] =
665:             ext_authz_duration_value;
666:       }
667:       decoder_callbacks_->streamInfo().setDynamicMetadata("envoy.filters.http.ext_authz",
668:                                                           response->dynamic_metadata);
669:     }
670:   }
671: 
672:   switch (response->status) {
673:   case CheckStatus::OK: {
674:     // Any changes to request headers or query parameters can affect how the request is going to be
675:     // routed. If we are changing the headers we also need to clear the route
676:     // cache.
677:     if (config_->clearRouteCache() &&
678:         (!response->headers_to_set.empty() || !response->headers_to_append.empty() ||
679:          !response->headers_to_remove.empty() || !response->query_parameters_to_set.empty() ||
680:          !response->query_parameters_to_remove.empty())) {
681:       ENVOY_STREAM_LOG(debug, "ext_authz is clearing route cache", *decoder_callbacks_);
682:       decoder_callbacks_->downstreamCallbacks()->clearRouteCache();
683:     }
684: 
685:     ENVOY_STREAM_LOG(trace,
686:                      "ext_authz filter added header(s) to the request:", *decoder_callbacks_);
687:     for (const auto& [key, value] : response->headers_to_set) {
688:       CheckResult check_result = validateAndCheckDecoderHeaderMutation(
689:           Filters::Common::MutationRules::CheckOperation::SET, key, value);
690:       switch (check_result) {
691:       case CheckResult::OK:
692:         ENVOY_STREAM_LOG(trace, "'{}':'{}'", *decoder_callbacks_, key, value);
693:         request_headers_->setCopy(Http::LowerCaseString(key), value);
694:         if (!headersWithinLimits(*request_headers_)) {
695:           stats_.request_header_limits_reached_.inc();
696:           rejectResponse();
697:           return;
698:         }
699:         break;
700:       case CheckResult::IGNORE:
701:         ENVOY_STREAM_LOG(trace, "Ignoring invalid header to set '{}':'{}'.", *decoder_callbacks_,
702:                          key, value);
703:         break;
704:       case CheckResult::FAIL:
705:         ENVOY_STREAM_LOG(trace, "Rejecting invalid header to set '{}':'{}'.", *decoder_callbacks_,
706:                          key, value);
707:         rejectResponse();
708:         return;
709:       }
710:     }
711:     for (const auto& [key, value] : response->headers_to_add) {
712:       CheckResult check_result = validateAndCheckDecoderHeaderMutation(
713:           Filters::Common::MutationRules::CheckOperation::SET, key, value);
714:       switch (check_result) {
715:       case CheckResult::OK:
716:         ENVOY_STREAM_LOG(trace, "'{}':'{}'", *decoder_callbacks_, key, value);
717:         request_headers_->addCopy(Http::LowerCaseString(key), value);
718:         if (!headersWithinLimits(*request_headers_)) {
719:           stats_.request_header_limits_reached_.inc();
720:           rejectResponse();
721:           return;
722:         }
723:         break;
724:       case CheckResult::IGNORE:
725:         ENVOY_STREAM_LOG(trace, "Ignoring invalid header to add '{}':'{}'.", *decoder_callbacks_,
726:                          key, value);
727:         break;
728:       case CheckResult::FAIL:
729:         ENVOY_STREAM_LOG(trace, "Rejecting invalid header to add '{}':'{}'.", *decoder_callbacks_,
730:                          key, value);
731:         rejectResponse();
732:         return;
733:       }
734:     }
735:     for (const auto& [key, value] : response->headers_to_append) {
736:       CheckResult check_result = validateAndCheckDecoderHeaderMutation(
737:           Filters::Common::MutationRules::CheckOperation::APPEND, key, value);
738:       switch (check_result) {
739:       case CheckResult::OK: {
740:         ENVOY_STREAM_LOG(trace, "'{}':'{}'", *decoder_callbacks_, key, value);
741:         Http::LowerCaseString lowercase_key(key);
742:         const auto header_to_modify = request_headers_->get(lowercase_key);
743:         // TODO(dio): Add a flag to allow appending non-existent headers, without setting it
744:         // first (via `headers_to_add`). For example, given:
745:         // 1. Original headers {"original": "true"}
746:         // 2. Response headers from the authorization servers {{"append": "1"}, {"append":
747:         // "2"}}
748:         //
749:         // Currently it is not possible to add {{"append": "1"}, {"append": "2"}} (the
750:         // intended combined headers: {{"original": "true"}, {"append": "1"}, {"append":
751:         // "2"}}) to the request to upstream server by only sets `headers_to_append`.
752:         if (!header_to_modify.empty()) {
753:           ENVOY_STREAM_LOG(trace, "'{}':'{}'", *decoder_callbacks_, key, value);
754:           // The current behavior of appending is by combining entries with the same key,
755:           // into one entry. The value of that combined entry is separated by ",".
756:           // TODO(dio): Consider to use addCopy instead.
757:           request_headers_->appendCopy(lowercase_key, value);
758:           if (!headersWithinLimits(*request_headers_)) {
759:             stats_.request_header_limits_reached_.inc();
760:             rejectResponse();
761:             return;
762:           }
763:         }
764:         break;
765:       }
766:       case CheckResult::IGNORE:
767:         ENVOY_STREAM_LOG(trace, "Ignoring invalid header to append '{}':'{}'.", *decoder_callbacks_,
768:                          key, value);
769:         break;
770:       case CheckResult::FAIL:
771:         ENVOY_STREAM_LOG(trace, "Rejecting invalid header to append '{}':'{}'.",
772:                          *decoder_callbacks_, key, value);
773:         rejectResponse();
774:         return;
775:       }
776:     }
777: 
778:     ENVOY_STREAM_LOG(trace,
779:                      "ext_authz filter removed header(s) from the request:", *decoder_callbacks_);
780:     for (const auto& key : response->headers_to_remove) {
781:       // If the response contains an invalid header to remove, it's the same as trying to remove a
782:       // header that doesn't exist, so just ignore it.
783:       if (config_->validateMutations() && !Http::HeaderUtility::headerNameIsValid(key)) {
784:         ENVOY_STREAM_LOG(trace, "Ignoring invalid header removal '{}'.", *decoder_callbacks_, key);
785:         continue;
786:       }
787:       // We don't allow removing any :-prefixed headers, nor Host, as removing them would make the
788:       // request malformed. checkDecoderHeaderMutation also performs this check, however, so only
789:       // perform this check explicitly if decoder header mutation rules is empty.
790:       if (!config_->hasDecoderHeaderMutationRules() &&
791:           !Http::HeaderUtility::isRemovableHeader(key)) {
792:         ENVOY_STREAM_LOG(trace, "Ignoring invalid header removal '{}'.", *decoder_callbacks_, key);
793:         continue;
794:       }
795:       // Check header mutation is valid according to configured decoder header mutation rules.
796:       Http::LowerCaseString lowercase_key(key);
797:       switch (config_->checkDecoderHeaderMutation(CheckOperation::REMOVE, lowercase_key,
798:                                                   EMPTY_STRING)) {
799:       case CheckResult::OK:
800:         ENVOY_STREAM_LOG(trace, "'{}'", *decoder_callbacks_, key);
801:         request_headers_->remove(lowercase_key);
802:         if (!headersWithinLimits(*request_headers_)) {
803:           stats_.request_header_limits_reached_.inc();
804:           rejectResponse();
805:           return;
806:         }
807:         break;
808:       case CheckResult::IGNORE:
809:         ENVOY_STREAM_LOG(trace, "Ignoring disallowed header removal '{}'.", *decoder_callbacks_,
810:                          key);
811:         break;
812:       case CheckResult::FAIL:
813:         ENVOY_STREAM_LOG(trace, "Rejecting disallowed header removal '{}'.", *decoder_callbacks_,
814:                          key);
815:         rejectResponse();
816:         return;
817:       }
818:     }
819: 
820:     if (!response->response_headers_to_add.empty()) {
821:       ENVOY_STREAM_LOG(trace, "ext_authz filter saving {} header(s) to add to the response:",
822:                        *decoder_callbacks_, response->response_headers_to_add.size());
823:       for (const auto& [key, value] : response->response_headers_to_add) {
824:         if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
825:                                              !Http::HeaderUtility::headerValueIsValid(value))) {
826:           ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
827:                            value);
828:           rejectResponse();
829:           return;
830:         }
831:       }
832:       response_headers_to_add_ = Http::HeaderVector{response->response_headers_to_add.begin(),
833:                                                     response->response_headers_to_add.end()};
834:     }
835: 
836:     if (!response->response_headers_to_set.empty()) {
837:       ENVOY_STREAM_LOG(trace, "ext_authz filter saving {} header(s) to set to the response:",
838:                        *decoder_callbacks_, response->response_headers_to_set.size());
839:       for (const auto& [key, value] : response->response_headers_to_set) {
840:         if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
841:                                              !Http::HeaderUtility::headerValueIsValid(value))) {
842:           ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
843:                            value);
844:           rejectResponse();
845:           return;
846:         }
847:       }
848:       response_headers_to_set_ = Http::HeaderVector{response->response_headers_to_set.begin(),
849:                                                     response->response_headers_to_set.end()};
850:     }
851: 
852:     if (!response->response_headers_to_add_if_absent.empty()) {
853:       ENVOY_STREAM_LOG(trace, "ext_authz filter saving {} header(s) to add to the response:",
854:                        *decoder_callbacks_, response->response_headers_to_add_if_absent.size());
855:       for (const auto& [key, value] : response->response_headers_to_add_if_absent) {
856:         if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
857:                                              !Http::HeaderUtility::headerValueIsValid(value))) {
858:           ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
859:                            value);
860:           rejectResponse();
861:           return;
862:         }
863:       }
864:       response_headers_to_add_if_absent_ =
865:           Http::HeaderVector{response->response_headers_to_add_if_absent.begin(),
866:                              response->response_headers_to_add_if_absent.end()};
867:     }
868: 
869:     if (!response->response_headers_to_overwrite_if_exists.empty()) {
870:       ENVOY_STREAM_LOG(trace, "ext_authz filter saving {} header(s) to set to the response:",
871:                        *decoder_callbacks_,
872:                        response->response_headers_to_overwrite_if_exists.size());
873:       for (const auto& [key, value] : response->response_headers_to_overwrite_if_exists) {
874:         if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
875:                                              !Http::HeaderUtility::headerValueIsValid(value))) {
876:           ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
877:                            value);
878:           rejectResponse();
879:           return;
880:         }
881:       }
882:       response_headers_to_overwrite_if_exists_ =
883:           Http::HeaderVector{response->response_headers_to_overwrite_if_exists.begin(),
884:                              response->response_headers_to_overwrite_if_exists.end()};
885:     }
886: 
887:     absl::optional<Http::Utility::QueryParamsMulti> modified_query_parameters;
888:     if (!response->query_parameters_to_set.empty()) {
889:       modified_query_parameters = Http::Utility::QueryParamsMulti::parseQueryString(
890:           request_headers_->Path()->value().getStringView());
891:       ENVOY_STREAM_LOG(
892:           trace, "ext_authz filter set query parameter(s) on the request:", *decoder_callbacks_);
893:       for (const auto& [key, value] : response->query_parameters_to_set) {
894:         if (config_->validateMutations() &&
895:             (!Http::Utility::PercentEncoding::queryParameterIsUrlEncoded(key) ||
896:              !Http::Utility::PercentEncoding::queryParameterIsUrlEncoded(value))) {
897:           ENVOY_STREAM_LOG(trace, "Rejected invalid query parameter {}={}.", *decoder_callbacks_,
898:                            key, value);
899:           rejectResponse();
900:           return;
901:         }
902:         ENVOY_STREAM_LOG(trace, "'{}={}'", *decoder_callbacks_, key, value);
903:         modified_query_parameters->overwrite(key, value);
904:       }
905:     }
906: 
907:     if (!response->query_parameters_to_remove.empty()) {
908:       if (!modified_query_parameters) {
909:         modified_query_parameters = Http::Utility::QueryParamsMulti::parseQueryString(
910:             request_headers_->Path()->value().getStringView());
911:       }
912:       ENVOY_STREAM_LOG(trace, "ext_authz filter removed query parameter(s) from the request:",
913:                        *decoder_callbacks_);
914:       for (const auto& key : response->query_parameters_to_remove) {
915:         ENVOY_STREAM_LOG(trace, "'{}'", *decoder_callbacks_, key);
916:         modified_query_parameters->remove(key);
917:       }
918:     }
919: 
920:     // We modified the query parameters in some way, so regenerate the `path` header and set it
921:     // here.
922:     if (modified_query_parameters) {
923:       const auto new_path =
924:           modified_query_parameters->replaceQueryString(request_headers_->Path()->value());
925:       ENVOY_STREAM_LOG(
926:           trace, "ext_authz filter modified query parameter(s), using new path for request: {}",
927:           *decoder_callbacks_, new_path);
928:       request_headers_->setPath(new_path);
929:       if (!headersWithinLimits(*request_headers_)) {
930:         stats_.request_header_limits_reached_.inc();
931:         rejectResponse();
932:         return;
933:       }
934:     }
935: 
936:     if (cluster_) {
937:       config_->incCounter(cluster_->statsScope(), config_->ext_authz_ok_);
938:     }
939:     stats_.ok_.inc();
940:     continueDecoding();
941:     break;
942:   }
943: 
944:   case CheckStatus::Denied: {
945:     ENVOY_STREAM_LOG(trace, "ext_authz filter rejected the request. Response status code: '{}'",
946:                      *decoder_callbacks_, enumToInt(response->status_code));
947:     stats_.denied_.inc();
948: 
949:     if (cluster_) {
950:       config_->incCounter(cluster_->statsScope(), config_->ext_authz_denied_);
951:       if (config_->chargeClusterResponseStats()) {
952:         Http::CodeStats::ResponseStatInfo info{config_->scope(),
953:                                                cluster_->statsScope(),
954:                                                empty_stat_name,
955:                                                enumToInt(response->status_code),
956:                                                true,
957:                                                empty_stat_name,
958:                                                empty_stat_name,
959:                                                empty_stat_name,
960:                                                empty_stat_name,
961:                                                empty_stat_name,
962:                                                false};
963:         config_->httpContext().codeStats().chargeResponseStat(info, false);
964:       }
965:     }
966: 
967:     // Check headers are valid.
968:     if (config_->validateMutations()) {
969:       for (const auto& [key, value] : response->headers_to_set) {
970:         if (!Http::HeaderUtility::headerNameIsValid(key) ||
971:             !Http::HeaderUtility::headerValueIsValid(value)) {
972:           ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
973:                            value);
974:           rejectResponse();
975:           return;
976:         }
977:       }
978:     }
979: 
980:     if (config_->maxDeniedResponseBodyBytes() > 0 &&
981:         response->body.length() > config_->maxDeniedResponseBodyBytes()) {
982:       ENVOY_STREAM_LOG(
983:           trace, "ext_authz filter is truncating the response body from {} to {} bytes.",
984:           *decoder_callbacks_, response->body.length(), config_->maxDeniedResponseBodyBytes());
985:       response->body.resize(config_->maxDeniedResponseBodyBytes());
986:     }
987: 
988:     // setResponseFlag must be called before sendLocalReply
989:     decoder_callbacks_->streamInfo().setResponseFlag(
990:         StreamInfo::CoreResponseFlag::UnauthorizedExternalService);
991:     decoder_callbacks_->sendLocalReply(
992:         response->status_code, response->body,
993:         [&headers = response->headers_to_set, &callbacks = *decoder_callbacks_,
994:          this](Http::HeaderMap& response_headers) -> void {
995:           ENVOY_STREAM_LOG(trace,
996:                            "ext_authz filter added header(s) to the local response:", callbacks);
997:           // Firstly, remove all headers requested by the ext_authz filter, to ensure that they will
998:           // override existing headers.
999:           for (const auto& [key, _] : headers) {
1000:             response_headers.remove(Http::LowerCaseString(key));
1001:           }
1002:           // Then set all of the requested headers, allowing the same header to be set multiple
1003:           // times, e.g. `Set-Cookie`.
1004:           for (const auto& [key, value] : headers) {
1005:             if (config_->enforceResponseHeaderLimits() &&
1006:                 response_headers.size() >= response_headers.maxHeadersCount()) {
1007:               stats_.omitted_response_headers_.inc();
1008:               ENVOY_LOG_EVERY_POW_2(
1009:                   warn,
1010:                   "Some ext_authz response headers weren't added because the header map was full.");
1011:               break;
1012:             }
1013:             ENVOY_STREAM_LOG(trace, " '{}':'{}'", callbacks, key, value);
1014:             response_headers.addCopy(Http::LowerCaseString(key), value);
1015:           }
1016:         },
1017:         absl::nullopt, Filters::Common::ExtAuthz::ResponseCodeDetails::get().AuthzDenied);
1018:     break;
1019:   }
1020: 
1021:   case CheckStatus::Error: {
1022:     if (cluster_) {
1023:       config_->incCounter(cluster_->statsScope(), config_->ext_authz_error_);
1024:     }
1025:     stats_.error_.inc();
1026: 
1027:     // Validate error response headers and clear custom attributes if invalid.
1028:     validateAndClearInvalidErrorResponseAttributes(response);
1029: 
1030:     // Apply max_denied_response_body_bytes limit to error response body as well.
1031:     if (config_->maxDeniedResponseBodyBytes() > 0 &&
1032:         response->body.length() > config_->maxDeniedResponseBodyBytes()) {
1033:       ENVOY_STREAM_LOG(
1034:           trace, "ext_authz filter is truncating the error response body from {} to {} bytes.",
1035:           *decoder_callbacks_, response->body.length(), config_->maxDeniedResponseBodyBytes());
1036:       response->body.resize(config_->maxDeniedResponseBodyBytes());
1037:     }
1038: 
1039:     if (config_->failureModeAllow()) {
1040:       ENVOY_STREAM_LOG(trace, "ext_authz filter allowed the request with error",
1041:                        *decoder_callbacks_);
1042:       stats_.failure_mode_allowed_.inc();
1043:       if (cluster_) {
1044:         config_->incCounter(cluster_->statsScope(), config_->ext_authz_failure_mode_allowed_);
1045:       }
1046:       if (config_->failureModeAllowHeaderAdd()) {
1047:         request_headers_->addReferenceKey(
1048:             Filters::Common::ExtAuthz::Headers::get().EnvoyAuthFailureModeAllowed, "true");
1049:       }
1050:       continueDecoding();
1051:     } else {
1052:       // Use custom status code from error_response if provided, otherwise use status_on_error.
1053:       // Status code 0 means not set.
1054:       const Http::Code status_code = response->status_code != static_cast<Http::Code>(0)
1055:                                          ? response->status_code
1056:                                          : config_->statusOnError();
1057:       ENVOY_STREAM_LOG(
1058:           trace, "ext_authz filter rejected the request with an error. Response status code: {}",
1059:           *decoder_callbacks_, enumToInt(status_code));
1060:       decoder_callbacks_->streamInfo().setResponseFlag(
1061:           StreamInfo::CoreResponseFlag::UnauthorizedExternalService);
1062: 
1063:       decoder_callbacks_->sendLocalReply(
1064:           status_code, response->body,
1065:           [&headers_to_set = response->headers_to_set,
1066:            &headers_to_append = response->headers_to_append,
1067:            this](Http::HeaderMap& response_headers) -> void {
1068:             addErrorResponseHeaders(response_headers, headers_to_set, headers_to_append);
1069:           },
1070:           absl::nullopt, Filters::Common::ExtAuthz::ResponseCodeDetails::get().AuthzError);
1071:     }
1072:     break;
1073:   }
1074:   }
1075: }
1076: 
1077: void Filter::responseHeaderLimitsReached() {
1078:   const Http::Code status = Http::Code::InternalServerError;
1079:   ENVOY_LOG_EVERY_POW_2(warn,
1080:                         "ext_authz filter couldn't add all response header mutations. "
1081:                         "Sending local reply with response status code: {}",
1082:                         enumToInt(status));
1083:   stats_.response_header_limits_reached_.inc();
1084:   encoder_callbacks_->streamInfo().setResponseFlag(
1085:       StreamInfo::CoreResponseFlag::UnauthorizedExternalService);
1086:   encoder_callbacks_->sendLocalReply(
1087:       status, EMPTY_STRING, nullptr, absl::nullopt,
1088:       Filters::Common::ExtAuthz::ResponseCodeDetails::get().AuthzInvalid);
1089: }
1090: 
1091: void Filter::rejectResponse() {
1092:   const Http::Code status = Http::Code::InternalServerError;
1093:   ENVOY_STREAM_LOG(trace, "ext_authz filter invalidated the response. Response status code: {}",
1094:                    *decoder_callbacks_, enumToInt(status));
1095:   if (cluster_) {
1096:     config_->incCounter(cluster_->statsScope(), config_->ext_authz_invalid_);
1097:   }
1098:   stats_.invalid_.inc();
1099:   decoder_callbacks_->streamInfo().setResponseFlag(
1100:       StreamInfo::CoreResponseFlag::UnauthorizedExternalService);
1101:   decoder_callbacks_->sendLocalReply(
1102:       status, EMPTY_STRING, nullptr, absl::nullopt,
1103:       Filters::Common::ExtAuthz::ResponseCodeDetails::get().AuthzInvalid);
1104: }
