1106: bool Filter::isBufferFull(uint64_t num_bytes_processing) const {
1107:   if (!allow_partial_message_) {
1108:     return false;
1109:   }
1110: 
1111:   uint64_t num_bytes_buffered = num_bytes_processing;
1112:   const auto* buffer = decoder_callbacks_->decodingBuffer();
1113:   if (buffer != nullptr) {
1114:     num_bytes_buffered += buffer->length();
1115:   }
1116: 
1117:   return num_bytes_buffered >= max_request_bytes_;
1118: }
