1120: void Filter::continueDecoding() {
1121:   // After sending the check request, we don't need to buffer the data anymore.
1122:   buffer_data_ = false;
1123: 
1124:   filter_return_ = FilterReturn::ContinueDecoding;
1125:   if (!initiating_call_) {
1126:     decoder_callbacks_->continueDecoding();
1127:   }
1128: }
