1130: Filter::PerRouteFlags Filter::getPerRouteFlags(const Router::RouteConstSharedPtr& route) const {
1131:   if (route == nullptr) {
1132:     return PerRouteFlags{true /*skip_check_*/, defaultCheckSettings()};
1133:   }
1134: 
1135:   const auto* specific_check_settings =
1136:       Http::Utility::resolveMostSpecificPerFilterConfig<FilterConfigPerRoute>(decoder_callbacks_);
1137:   if (specific_check_settings != nullptr) {
1138:     return PerRouteFlags{specific_check_settings->disabled(),
1139:                          specific_check_settings->checkSettings()};
1140:   }
1141: 
1142:   return PerRouteFlags{false /*skip_check_*/, defaultCheckSettings()};
1143: }
