1145: bool Filter::validateAndClearInvalidErrorResponseAttributes(
1146:     Filters::Common::ExtAuthz::ResponsePtr& response) {
1147:   if (!config_->validateMutations()) {
1148:     return true;
1149:   }
1150: 
1151:   // Validate headers_to_set.
1152:   for (const auto& [key, value] : response->headers_to_set) {
1153:     if (!Http::HeaderUtility::headerNameIsValid(key) ||
1154:         !Http::HeaderUtility::headerValueIsValid(value)) {
1155:       ENVOY_STREAM_LOG(trace, "Rejected invalid error header '{}':'{}'.", *decoder_callbacks_, key,
1156:                        value);
1157:       ENVOY_STREAM_LOG(info,
1158:                        "Custom error response from ext_authz will be ignored due to invalid "
1159:                        "header. Falling back to generic error response.",
1160:                        *decoder_callbacks_);
1161:       // Fall back to generic error by clearing all custom attributes.
1162:       response->headers_to_set.clear();
1163:       response->headers_to_append.clear();
1164:       response->body.clear();
1165:       response->status_code = static_cast<Http::Code>(0); // Clear custom status.
1166:       return false;
1167:     }
1168:   }
1169: 
1170:   // Validate headers_to_append.
1171:   for (const auto& [key, value] : response->headers_to_append) {
1172:     if (!Http::HeaderUtility::headerNameIsValid(key) ||
1173:         !Http::HeaderUtility::headerValueIsValid(value)) {
1174:       ENVOY_STREAM_LOG(trace, "Rejected invalid error header '{}':'{}'.", *decoder_callbacks_, key,
1175:                        value);
1176:       ENVOY_STREAM_LOG(info,
1177:                        "Custom error response from ext_authz will be ignored due to invalid "
1178:                        "header. Falling back to generic error response.",
1179:                        *decoder_callbacks_);
1180:       // Fall back to generic error by clearing all custom attributes.
1181:       response->headers_to_set.clear();
1182:       response->headers_to_append.clear();
1183:       response->body.clear();
1184:       response->status_code = static_cast<Http::Code>(0); // Clear custom status.
1185:       return false;
1186:     }
1187:   }
1188: 
1189:   return true;
1190: }
1191: 
1192: bool Filter::canAddResponseHeader(Http::HeaderMap& response_headers) {
1193:   if (config_->enforceResponseHeaderLimits() &&
1194:       response_headers.size() >= response_headers.maxHeadersCount()) {
1195:     stats_.omitted_response_headers_.inc();
1196:     ENVOY_LOG_EVERY_POW_2(warn, "Some ext_authz error response headers weren't added because the "
1197:                                 "header map was full.");
1198:     return false;
1199:   }
1200:   return true;
1201: }
1202: 
1203: void Filter::addErrorResponseHeaders(
1204:     Http::HeaderMap& response_headers,
1205:     const std::vector<std::pair<std::string, std::string>>& headers_to_set,
1206:     const std::vector<std::pair<std::string, std::string>>& headers_to_append) {
1207:   ENVOY_STREAM_LOG(trace,
1208:                    "ext_authz filter added header(s) to the error response:", *decoder_callbacks_);
1209: 
1210:   // First, handle headers_to_set which should override existing headers.
1211:   for (const auto& [key, _] : headers_to_set) {
1212:     response_headers.remove(Http::LowerCaseString(key));
1213:   }
1214:   for (const auto& [key, value] : headers_to_set) {
1215:     if (!canAddResponseHeader(response_headers)) {
1216:       break;
1217:     }
1218:     ENVOY_STREAM_LOG(trace, " '{}':'{}'", *decoder_callbacks_, key, value);
1219:     response_headers.addCopy(Http::LowerCaseString(key), value);
1220:   }
1221: 
1222:   // Then, handle headers_to_append which should append to existing headers.
1223:   for (const auto& [key, value] : headers_to_append) {
1224:     if (!canAddResponseHeader(response_headers)) {
1225:       break;
1226:     }
1227:     ENVOY_STREAM_LOG(trace, " '{}':'{}'", *decoder_callbacks_, key, value);
1228:     response_headers.addCopy(Http::LowerCaseString(key), value);
1229:   }
1230: }
