79: using UnsafeHeader = std::pair<std::string, std::string>;
80: using UnsafeHeaderVector = std::vector<UnsafeHeader>;
81: /**
82:  * Authorization response object for a RequestCallback.
83:  *
84:  * Header mutations and query parameter mutations are not expected to already be validated by the
85:  * client before packing them into this struct (hence they are "unsafe").
86:  */
87: struct Response {
88:   // Call status.
89:   CheckStatus status;
90:   // A set of HTTP headers returned by the authorization server, that will be optionally appended
91:   // to the request to the upstream server.
92:   UnsafeHeaderVector headers_to_append{};
93:   // A set of HTTP headers returned by the authorization server, will be optionally set
94:   // (using "setCopy") to the request to the upstream server.
95:   UnsafeHeaderVector headers_to_set{};
96:   // A set of HTTP headers returned by the authorization server, will be optionally added
97:   // (using "addCopy") to the request to the upstream server.
98:   UnsafeHeaderVector headers_to_add{};
99:   // A set of HTTP headers returned by the authorization server, will be optionally added
100:   // (using "addCopy") to the response sent back to the downstream client on OK auth
101:   // responses.
102:   UnsafeHeaderVector response_headers_to_add{};
103:   // A set of HTTP headers returned by the authorization server, will be optionally set (using
104:   // "setCopy") to the response sent back to the downstream client on OK auth responses.
105:   UnsafeHeaderVector response_headers_to_set{};
106:   // A set of HTTP headers returned by the authorization server, will be optionally added
107:   // (using "addCopy") to the response sent back to the downstream client on OK auth
108:   // responses only if the headers were not returned from the authz server.
109:   UnsafeHeaderVector response_headers_to_add_if_absent{};
110:   // A set of HTTP headers returned by the authorization server, will be optionally set (using
111:   // "setCopy") to the response sent back to the downstream client on OK auth responses
112:   // only if the headers were returned from the authz server.
113:   UnsafeHeaderVector response_headers_to_overwrite_if_exists{};
114:   // Whether the authorization server returned any headers with an invalid append action type.
115:   bool saw_invalid_append_actions{false};
116:   // A set of HTTP headers consumed by the authorization server, will be removed
117:   // from the request to the upstream server.
118:   std::vector<std::string> headers_to_remove{};
119:   // A set of query string parameters to be set (possibly overwritten) on the
120:   // request to the upstream server.
121:   Http::Utility::QueryParamsVector query_parameters_to_set{};
122:   // A set of query string parameters to remove from the request to the upstream server.
123:   std::vector<std::string> query_parameters_to_remove{};
124:   // Optional http body used only on denied response.
125:   std::string body{};
126:   // Optional http status used only on denied response.
127:   Http::Code status_code{};
128: 
129:   // A set of metadata returned by the authorization server, that will be emitted as filter's
130:   // dynamic metadata that other filters can leverage.
131:   Protobuf::Struct dynamic_metadata{};
132: 
133:   // The gRPC status returned by the authorization server when it is making a
134:   // gRPC call.
135:   absl::optional<Grpc::Status::GrpcStatus> grpc_status{absl::nullopt};
