19: void copyHeaderFieldIntoResponse(
20:     ResponsePtr& response,
21:     const Protobuf::RepeatedPtrField<envoy::config::core::v3::HeaderValueOption>& headers) {
22:   for (const auto& header : headers) {
23:     if (header.append().value()) {
24:       response->headers_to_append.emplace_back(header.header().key(), header.header().value());
25:     } else {
26:       response->headers_to_set.emplace_back(header.header().key(), header.header().value());
27:     }
28:   }
29: }
30: 
31: void copyOkResponseMutations(ResponsePtr& response,
32:                              const envoy::service::auth::v3::OkHttpResponse& ok_response) {
33:   copyHeaderFieldIntoResponse(response, ok_response.headers());
34: 
35:   for (const auto& header : ok_response.response_headers_to_add()) {
36:     if (header.has_append()) {
37:       if (header.append().value()) {
38:         response->response_headers_to_add.emplace_back(header.header().key(),
39:                                                        header.header().value());
40:       } else {
41:         response->response_headers_to_set.emplace_back(header.header().key(),
42:                                                        header.header().value());
43:       }
44:     } else {
45:       switch (header.append_action()) {
46:       case Router::HeaderValueOption::APPEND_IF_EXISTS_OR_ADD:
47:         response->response_headers_to_add.emplace_back(header.header().key(),
48:                                                        header.header().value());
49:         break;
50:       case Router::HeaderValueOption::ADD_IF_ABSENT:
51:         response->response_headers_to_add_if_absent.emplace_back(header.header().key(),
52:                                                                  header.header().value());
53:         break;
54:       case Router::HeaderValueOption::OVERWRITE_IF_EXISTS:
55:         response->response_headers_to_overwrite_if_exists.emplace_back(header.header().key(),
56:                                                                        header.header().value());
57:         break;
58:       case Router::HeaderValueOption::OVERWRITE_IF_EXISTS_OR_ADD:
59:         response->response_headers_to_set.emplace_back(header.header().key(),
60:                                                        header.header().value());
61:         break;
62:       default:
63:         response->saw_invalid_append_actions = true;
64:         break;
65:       }
66:     }
67:   }
68: 
69:   response->headers_to_remove = std::vector<std::string>{ok_response.headers_to_remove().begin(),
70:                                                          ok_response.headers_to_remove().end()};
71: 
72:   for (const auto& query_parameter : ok_response.query_parameters_to_set()) {
73:     response->query_parameters_to_set.emplace_back(query_parameter.key(), query_parameter.value());
74:   }
75: 
76:   response->query_parameters_to_remove =
77:       std::vector<std::string>{ok_response.query_parameters_to_remove().begin(),
78:                                ok_response.query_parameters_to_remove().end()};
79: }
