81: GrpcClientImpl::GrpcClientImpl(const Grpc::RawAsyncClientSharedPtr& async_client,
82:                                const absl::optional<std::chrono::milliseconds>& timeout)
83:     : async_client_(async_client), timeout_(timeout),
84:       service_method_(*Protobuf::DescriptorPool::generated_pool()->FindMethodByName(
85:           "envoy.service.auth.v3.Authorization.Check")) {}
