38: // configuration.
39: const Response& errorResponse() {
40:   CONSTRUCT_ON_FIRST_USE(Response, Response{CheckStatus::Error,
41:                                             UnsafeHeaderVector{},
42:                                             UnsafeHeaderVector{},
43:                                             UnsafeHeaderVector{},
44:                                             UnsafeHeaderVector{},
