57: // Static matcher that never matches anything. Used for matchers that are not applicable
58: // in certain response contexts (e.g., upstream headers for denied responses).
59: const MatcherSharedPtr& neverMatchingMatcher() {
60:   CONSTRUCT_ON_FIRST_USE(MatcherSharedPtr, std::make_shared<HeaderKeyMatcher>(
61:                                                std::vector<Matchers::StringMatcherPtr>{}));
62: }
63: 
64: // SuccessResponse used for creating either DENIED or OK authorization responses.
65: struct SuccessResponse {
66:   SuccessResponse(const Http::HeaderMap& headers, const MatcherSharedPtr& matchers,
67:                   const MatcherSharedPtr& append_matchers,
68:                   const MatcherSharedPtr& response_matchers,
69:                   const MatcherSharedPtr& dynamic_metadata_matchers, Response&& response)
70:       : headers_(headers), matchers_(matchers), append_matchers_(append_matchers),
71:         response_matchers_(response_matchers),
72:         to_dynamic_metadata_matchers_(dynamic_metadata_matchers),
73:         response_(std::make_unique<Response>(response)) {
74:     headers_.iterate([this](const Http::HeaderEntry& header) -> Http::HeaderMap::Iterate {
75:       // UpstreamHeaderMatcher
76:       if (matchers_->matches(header.key().getStringView())) {
77:         response_->headers_to_set.emplace_back(header.key().getStringView(),
78:                                                header.value().getStringView());
79:       }
80:       if (append_matchers_->matches(header.key().getStringView())) {
81:         // If there is an existing matching key in the current headers, the new entry will be
82:         // appended with the same key. For example, given {"key": "value1"} headers, if there is
83:         // a matching "key" from the authorization response headers {"key": "value2"}, the
84:         // request to upstream server will have two entries for "key": {"key": "value1", "key":
85:         // "value2"}.
86:         response_->headers_to_add.emplace_back(header.key().getStringView(),
87:                                                header.value().getStringView());
88:       }
89:       if (response_matchers_->matches(header.key().getStringView())) {
90:         // For HTTP implementation, the response headers from the auth server will, by default, be
91:         // appended (using addCopy) to the encoded response headers.
92:         response_->response_headers_to_add.emplace_back(header.key().getStringView(),
93:                                                         header.value().getStringView());
94:       }
95:       if (to_dynamic_metadata_matchers_->matches(header.key().getStringView())) {
96:         const std::string key{header.key().getStringView()};
97:         const std::string value{header.value().getStringView()};
98:         (*response_->dynamic_metadata.mutable_fields())[key] = ValueUtil::stringValue(value);
99:       }
100:       return Http::HeaderMap::Iterate::Continue;
101:     });
102:   }
103: 
104:   const Http::HeaderMap& headers_;
105:   // All matchers below are used on headers_.
106:   const MatcherSharedPtr& matchers_;
107:   const MatcherSharedPtr& append_matchers_;
108:   const MatcherSharedPtr& response_matchers_;
109:   const MatcherSharedPtr& to_dynamic_metadata_matchers_;
110:   ResponsePtr response_;
111: };
