113: absl::StatusOr<std::string> validatePathPrefix(absl::string_view path_prefix) {
114:   if (!path_prefix.empty() && path_prefix[0] != '/') {
115:     return absl::InvalidArgumentError("path_prefix should start with \"/\".");
116:   }
