120: absl::StatusOr<Router::RetryPolicyConstSharedPtr>
121: createRetryPolicy(const envoy::config::core::v3::RetryPolicy& core_retry_policy,
122:                   Server::Configuration::CommonFactoryContext& context) {
123:   // Convert core retry policy to route retry policy and create the implementation.
124:   // By default when runtime flag is true, pass empty string to respect user's configured
125:   // retry_on, not override it. When flag is false, use hardcoded defaults for backwards
126:   // compatibility.
127:   const std::string default_retry_on =
128:       Runtime::runtimeFeatureEnabled(
129:           "envoy.reloadable_features.ext_authz_http_client_retries_respect_user_retry_on")
130:           ? ""
131:           : "5xx,gateway-error,connect-failure,reset";
132:   envoy::config::route::v3::RetryPolicy route_retry_policy =
133:       Http::Utility::convertCoreToRouteRetryPolicy(core_retry_policy, default_retry_on);
134: 
135:   return Router::RetryPolicyImpl::create(route_retry_policy, context.messageValidationVisitor(),
136:                                          context);
137: }
