217: MatcherSharedPtr
218: ClientConfig::toClientMatchers(const envoy::type::matcher::v3::ListStringMatcher& list,
219:                                Server::Configuration::CommonFactoryContext& context) {
220:   std::vector<Matchers::StringMatcherPtr> matchers(
221:       CheckRequestUtils::createStringMatchers(list, context));
222: 
223:   // If list is empty, all authorization response headers, except Host, should be added to
224:   // the client response.
225:   if (matchers.empty()) {
226:     envoy::type::matcher::v3::StringMatcher matcher;
227:     matcher.set_exact(Http::Headers::get().Host.get());
228:     matchers.push_back(std::make_unique<Matchers::StringMatcherImpl>(matcher, context));
229: 
230:     return std::make_shared<NotHeaderKeyMatcher>(std::move(matchers));
231:   }
232: 
233:   // If not empty, all user defined matchers and default matcher's list will
234:   // be used instead.
235:   std::vector<Http::LowerCaseString> keys{
236:       {Http::Headers::get().Status, Http::Headers::get().ContentLength,
237:        Http::Headers::get().WWWAuthenticate, Http::Headers::get().Location}};
238: 
239:   for (const auto& key : keys) {
240:     envoy::type::matcher::v3::StringMatcher matcher;
241:     matcher.set_exact(key.get());
242:     matchers.push_back(std::make_unique<Matchers::StringMatcherImpl>(matcher, context));
243:   }
244: 
245:   return std::make_shared<HeaderKeyMatcher>(std::move(matchers));
246: }
