265: // Client
266: void RawHttpClientImpl::check(RequestCallbacks& callbacks,
267:                               const envoy::service::auth::v3::CheckRequest& request,
268:                               Tracing::Span& parent_span,
269:                               const StreamInfo::StreamInfo& stream_info) {
270:   ASSERT(callbacks_ == nullptr);
271:   callbacks_ = &callbacks;
272: 
273:   Http::RequestHeaderMapPtr headers;
274: 
275:   const auto& http_request = request.attributes().request().http();
276:   const auto& http_request_body =
277:       http_request.body().empty() ? http_request.raw_body() : http_request.body();
278: 
279:   uint64_t request_length = http_request_body.size();
280: 
281:   if (request_length > 0) {
282:     headers = Http::createHeaderMap<Http::RequestHeaderMapImpl>(
283:         {{Http::Headers::get().ContentLength, std::to_string(request_length)}});
284:   } else {
285:     headers = Http::createHeaderMap<Http::RequestHeaderMapImpl>(lengthZeroHeader());
286:   }
287: 
288:   if (config_->encodeRawHeaders()) {
289:     for (const auto& header : http_request.header_map().headers()) {
290:       const Http::LowerCaseString key{header.key()};
291: 
292:       // Skip setting content-length header since it is already configured at initialization.
293:       if (key == Http::Headers::get().ContentLength) {
294:         continue;
295:       }
296: 
297:       if (key == Http::Headers::get().Path && !config_->pathPrefix().empty()) {
298:         headers->addCopy(key, absl::StrCat(config_->pathPrefix(), header.raw_value()));
299:       } else {
300:         headers->addCopy(key, header.raw_value());
301:       }
302:     }
303:   } else {
304:     for (const auto& header : http_request.headers()) {
305:       const Http::LowerCaseString key{header.first};
306: 
307:       // Skip setting content-length header since it is already configured at initialization.
308:       if (key == Http::Headers::get().ContentLength) {
309:         continue;
310:       }
311: 
312:       if (key == Http::Headers::get().Path && !config_->pathPrefix().empty()) {
313:         headers->addCopy(key, absl::StrCat(config_->pathPrefix(), header.second));
314:       } else {
315:         headers->addCopy(key, header.second);
316:       }
317:     }
318:   }
319: 
320:   config_->requestHeaderParser().evaluateHeaders(*headers, stream_info);
321: 
322:   Http::RequestMessagePtr message =
323:       std::make_unique<Envoy::Http::RequestMessageImpl>(std::move(headers));
324:   if (request_length > 0) {
325:     message->body().add(http_request_body);
326:   }
327: 
328:   const std::string& cluster = config_->cluster();
329: 
330:   // It's possible that the cluster specified in the filter configuration no longer exists due to a
331:   // CDS removal.
332:   const auto thread_local_cluster = cm_.getThreadLocalCluster(cluster);
333:   if (thread_local_cluster == nullptr) {
334:     // TODO(dio): Add stats related to this.
335:     ENVOY_LOG(debug, "ext_authz cluster '{}' does not exist", cluster);
336:     callbacks_->onComplete(std::make_unique<Response>(errorResponse()));
337:     callbacks_ = nullptr;
338:   } else {
339:     // Do not enforce a sampling decision on this span; instead keep the parent's sampling status.
340:     auto options = Http::AsyncClient::RequestOptions()
341:                        .setTimeout(config_->timeout())
342:                        .setParentSpan(parent_span)
343:                        .setChildSpanName(config_->tracingName())
344:                        .setSampled(absl::nullopt);
345: 
346:     options.setSendXff(false);
347: 
348:     // Apply retry policy if configured.
349:     if (config_->retryPolicy() != nullptr) {
350:       options.setRetryPolicy(config_->retryPolicy());
351:       options.setBufferBodyForRetry(true);
352:     }
353: 
354:     request_ = thread_local_cluster->httpAsyncClient().send(std::move(message), *this, options);
355:   }
356: }
