373: void RawHttpClientImpl::onBeforeFinalizeUpstreamSpan(
374:     Tracing::Span& span, const Http::ResponseHeaderMap* response_headers) {
375:   if (response_headers != nullptr) {
376:     const uint64_t status_code = Http::Utility::getResponseStatus(*response_headers);
377:     span.setTag(TracingConstants::get().HttpStatus,
378:                 Http::CodeUtility::toString(static_cast<Http::Code>(status_code)));
379:     span.setTag(TracingConstants::get().TraceStatus, status_code == enumToInt(Http::Code::OK)
380:                                                          ? TracingConstants::get().TraceOk
381:                                                          : TracingConstants::get().TraceUnauthz);
382:   }
