385: ResponsePtr RawHttpClientImpl::toResponse(Http::ResponseMessagePtr message) {
386:   const uint64_t status_code = Http::Utility::getResponseStatus(message->headers());
387: 
388:   // Set an error status if the call to the authorization server returns any of the 5xx HTTP error
389:   // codes. A Forbidden response is sent to the client if the filter has not been configured with
390:   // failure_mode_allow.
391:   if (Http::CodeUtility::is5xx(status_code)) {
392:     return std::make_unique<Response>(errorResponse());
393:   }
394: 
395:   // Extract headers-to-remove from the storage header coming from the
396:   // authorization server.
397:   const auto& storage_header_name = Headers::get().EnvoyAuthHeadersToRemove;
398:   // If we are going to construct an Ok response we need to save the
399:   // headers_to_remove in a variable first.
400:   std::vector<std::string> headers_to_remove;
401:   if (status_code == enumToInt(Http::Code::OK)) {
402:     const auto& get_result = message->headers().get(storage_header_name);
403:     for (size_t i = 0; i < get_result.size(); ++i) {
404:       const Http::HeaderEntry* entry = get_result[i];
405:       if (entry != nullptr) {
406:         absl::string_view storage_header_value = entry->value().getStringView();
407:         std::vector<absl::string_view> header_names = StringUtil::splitToken(
408:             storage_header_value, ",", /*keep_empty_string=*/false, /*trim_whitespace=*/true);
409:         headers_to_remove.reserve(headers_to_remove.size() + header_names.size());
410:         for (const auto& header_name : header_names) {
411:           headers_to_remove.emplace_back(header_name);
412:         }
413:       }
414:     }
415:   }
416:   // Now remove the storage header from the authz server response headers before
417:   // we reuse them to construct an Ok/Denied authorization response below.
418:   message->headers().remove(storage_header_name);
419: 
420:   // Create an Ok authorization response.
421:   if (status_code == enumToInt(Http::Code::OK)) {
422:     SuccessResponse ok{message->headers(),
423:                        config_->upstreamHeaderMatchers(),
424:                        config_->upstreamHeaderToAppendMatchers(),
425:                        config_->clientHeaderOnSuccessMatchers(),
426:                        config_->dynamicMetadataMatchers(),
427:                        Response{CheckStatus::OK,
428:                                 UnsafeHeaderVector{},
429:                                 UnsafeHeaderVector{},
430:                                 UnsafeHeaderVector{},
431:                                 UnsafeHeaderVector{},
432:                                 UnsafeHeaderVector{},
433:                                 UnsafeHeaderVector{},
434:                                 UnsafeHeaderVector{},
435:                                 false,
436:                                 std::move(headers_to_remove),
437:                                 Http::Utility::QueryParamsVector{},
438:                                 {},
439:                                 EMPTY_STRING,
440:                                 Http::Code::OK,
441:                                 Protobuf::Struct{}}};
442:     return std::move(ok.response_);
443:   }
444: 
445:   // Create a Denied authorization response.
446:   // For denied responses, only headers_to_set which is populated by the first matcher is
447:   // used by the ext_authz filter when sending the local reply. The headers_to_add and
448:   // response_headers_to_add fields are not used, so we pass a never-matching matcher.
449:   SuccessResponse denied{message->headers(),
450:                          config_->clientHeaderMatchers(),
451:                          neverMatchingMatcher(),
452:                          neverMatchingMatcher(),
453:                          config_->dynamicMetadataMatchers(),
454:                          Response{CheckStatus::Denied,
455:                                   UnsafeHeaderVector{},
456:                                   UnsafeHeaderVector{},
457:                                   UnsafeHeaderVector{},
458:                                   UnsafeHeaderVector{},
459:                                   UnsafeHeaderVector{},
460:                                   UnsafeHeaderVector{},
461:                                   UnsafeHeaderVector{},
462:                                   false,
463:                                   {{}},
464:                                   Http::Utility::QueryParamsVector{},
465:                                   {},
466:                                   message->bodyAsString(),
467:                                   static_cast<Http::Code>(status_code),
468:                                   Protobuf::Struct{}}};
469:   return std::move(denied.response_);
470: }
