46: /**
47:  * Global configuration for ExtAuthz filter.
48:  */
49: class Config {
50:   using LabelsMap = Protobuf::Map<std::string, std::string>;
51: 
52: public:
53:   Config(const envoy::extensions::filters::network::ext_authz::v3::ExtAuthz& config,
54:          Stats::Scope& scope, Server::Configuration::ServerFactoryContext& context)
55:       : stats_(generateStats(config.stat_prefix(), scope)),
56:         failure_mode_allow_(config.failure_mode_allow()),
57:         include_peer_certificate_(config.include_peer_certificate()),
58:         include_tls_session_(config.include_tls_session()),
59:         send_tls_alert_on_denial_(config.send_tls_alert_on_denial()),
60:         filter_enabled_metadata_(
61:             config.has_filter_enabled_metadata()
62:                 ? absl::optional<Matchers::MetadataMatcher>(
63:                       Matchers::MetadataMatcher(config.filter_enabled_metadata(), context))
64:                 : absl::nullopt),
65:         metadata_context_namespaces_(config.metadata_context_namespaces().begin(),
66:                                      config.metadata_context_namespaces().end()),
67:         typed_metadata_context_namespaces_(config.typed_metadata_context_namespaces().begin(),
68:                                            config.typed_metadata_context_namespaces().end()) {
69:     auto labels_key_it =
70:         context.bootstrap().node().metadata().fields().find(config.bootstrap_metadata_labels_key());
71:     if (labels_key_it != context.bootstrap().node().metadata().fields().end()) {
72:       for (const auto& labels_it : labels_key_it->second.struct_value().fields()) {
73:         destination_labels_[labels_it.first] = labels_it.second.string_value();
74:       }
75:     }
76:   }
77: 
78:   const InstanceStats& stats() { return stats_; }
79:   bool failureModeAllow() const { return failure_mode_allow_; }
80:   void setFailModeAllow(bool value) { failure_mode_allow_ = value; }
81:   bool includePeerCertificate() const { return include_peer_certificate_; }
82:   bool includeTLSSession() const { return include_tls_session_; }
83:   bool sendTlsAlertOnDenial() const { return send_tls_alert_on_denial_; }
84:   const LabelsMap& destinationLabels() const { return destination_labels_; }
85:   bool filterEnabledMetadata(const envoy::config::core::v3::Metadata& metadata) const {
86:     return filter_enabled_metadata_.has_value() ? filter_enabled_metadata_->match(metadata) : true;
87:   }
88:   const std::vector<std::string>& metadataContextNamespaces() const {
89:     return metadata_context_namespaces_;
90:   }
91:   const std::vector<std::string>& typedMetadataContextNamespaces() const {
92:     return typed_metadata_context_namespaces_;
93:   }
